import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String version;
    String description;
    String main;
    Exports exports;
    String types;
    Bin bin;
    List<String> files;
    Scripts scripts;
    Repository repository;
    List<String> keywords;
    Author author;
    List<Author> contributors;
    String license;
    Bugs bugs;
    String homepage;
    DevDependencies devDependencies;
    PeerDependencies peerDependencies;
    Map<String, PeerDependenciesMeta> peerDependenciesMeta;
    Dependencies dependencies;
    Prettier prettier;
    Volta volta;

    Package({
        required this.name,
        required this.version,
        required this.description,
        required this.main,
        required this.exports,
        required this.types,
        required this.bin,
        required this.files,
        required this.scripts,
        required this.repository,
        required this.keywords,
        required this.author,
        required this.contributors,
        required this.license,
        required this.bugs,
        required this.homepage,
        required this.devDependencies,
        required this.peerDependencies,
        required this.peerDependenciesMeta,
        required this.dependencies,
        required this.prettier,
        required this.volta,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        version: json["version"],
        description: json["description"],
        main: json["main"],
        exports: Exports.fromJson(json["exports"]),
        types: json["types"],
        bin: Bin.fromJson(json["bin"]),
        files: List<String>.from(json["files"].map((x) => x)),
        scripts: Scripts.fromJson(json["scripts"]),
        repository: Repository.fromJson(json["repository"]),
        keywords: List<String>.from(json["keywords"].map((x) => x)),
        author: Author.fromJson(json["author"]),
        contributors: List<Author>.from(json["contributors"].map((x) => Author.fromJson(x))),
        license: json["license"],
        bugs: Bugs.fromJson(json["bugs"]),
        homepage: json["homepage"],
        devDependencies: DevDependencies.fromJson(json["devDependencies"]),
        peerDependencies: PeerDependencies.fromJson(json["peerDependencies"]),
        peerDependenciesMeta: Map.from(json["peerDependenciesMeta"]).map((k, v) => MapEntry<String, PeerDependenciesMeta>(k, PeerDependenciesMeta.fromJson(v))),
        dependencies: Dependencies.fromJson(json["dependencies"]),
        prettier: Prettier.fromJson(json["prettier"]),
        volta: Volta.fromJson(json["volta"]),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "version": version,
        "description": description,
        "main": main,
        "exports": exports.toJson(),
        "types": types,
        "bin": bin.toJson(),
        "files": List<dynamic>.from(files.map((x) => x)),
        "scripts": scripts.toJson(),
        "repository": repository.toJson(),
        "keywords": List<dynamic>.from(keywords.map((x) => x)),
        "author": author.toJson(),
        "contributors": List<dynamic>.from(contributors.map((x) => x.toJson())),
        "license": license,
        "bugs": bugs.toJson(),
        "homepage": homepage,
        "devDependencies": devDependencies.toJson(),
        "peerDependencies": peerDependencies.toJson(),
        "peerDependenciesMeta": Map.from(peerDependenciesMeta).map((k, v) => MapEntry<String, dynamic>(k, v.toJson())),
        "dependencies": dependencies.toJson(),
        "prettier": prettier.toJson(),
        "volta": volta.toJson(),
    };
}

class Author {
    String name;
    String email;
    String url;

    Author({
        required this.name,
        required this.email,
        required this.url,
    });

    factory Author.fromJson(Map<String, dynamic> json) => Author(
        name: json["name"],
        email: json["email"],
        url: json["url"],
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "email": email,
        "url": url,
    };
}

